import './index.css';

import {
  useEffect,
  useState
} from 'react';

import TeacherHeader
from '../../components/common/TeacherHeader';

import {

  createSubject,
  getSubjects

} from '../../services/subjectService';

function SubjectManagementPage() {

  const [subjects, setSubjects] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  const [formData, setFormData] =
    useState({

      subject_name: '',
      semester: ''

    });

  // LOAD SUBJECTS

  const loadSubjects =
    async () => {

    try {

      const data =
        await getSubjects();

      console.log(data);

      setSubjects(data);

    } catch (error) {

      console.log(error);

    } finally {

      setLoading(false);

    }

  };

  useEffect(() => {

    loadSubjects();

  }, []);

  // HANDLE INPUT

  const handleChange =
    (e) => {

    setFormData({

      ...formData,

      [e.target.name]:
      e.target.value

    });

  };

  // SUBMIT FORM

  const handleSubmit =
    async (e) => {

    e.preventDefault();

    try {

      const response =
        await createSubject(formData);

      console.log(response);

      alert(
        'Subject Created Successfully'
      );

      // RESET FORM

      setFormData({

        subject_name: '',
        semester: ''

      });

      // RELOAD SUBJECTS

      loadSubjects();

    } catch (error) {

      console.log(error);

      alert(

        error.response?.data?.message ||

        error.response?.data?.error ||

        'Failed To Create Subject'

      );

    }

  };

  return (

    <div className="subject-page">

      {/* HEADER */}

      <TeacherHeader />


      {/* CONTENT */}

      <div className="subject-content">

        {/* TOP */}

        <div className="subject-top">

          <h1>
            Subject Management
          </h1>

          <p>
            Create and manage academic subjects
          </p>

        </div>


        {/* FORM */}

        <form
          className="subject-form"
          onSubmit={handleSubmit}
        >

          {/* SUBJECT NAME */}

          <div className="input-group">

            <label>
              Subject Name
            </label>

            <input
              type="text"
              name="subject_name"
              placeholder="Enter Subject Name"
              value={formData.subject_name}
              onChange={handleChange}
              required
            />

          </div>


          {/* SEMESTER */}

          <div className="input-group">

            <label>
              Semester
            </label>

            <input
              type="number"
              name="semester"
              placeholder="Enter Semester"
              value={formData.semester}
              onChange={handleChange}
              required
            />

          </div>


          {/* BUTTON */}

          <button type="submit">

            Create Subject

          </button>

        </form>


        {/* SUBJECT LIST */}

        <div className="subject-list-section">

          <h2>
            Available Subjects
          </h2>

          {

            loading
            ? (

              <div className="loading-box">

                Loading Subjects...

              </div>

            )
            : (

              <div className="subject-grid">

                {

                  subjects.length > 0
                  ? (

                    subjects.map((subject) => (

                      <div
                        key={subject.id}
                        className="subject-card"
                      >

                        <div className="subject-icon">

                          📘

                        </div>

                        <h3>
                          {subject.subject_name}
                        </h3>

                        <p>

                          <strong>
                            Subject ID:
                          </strong>

                          {' '}

                          {subject.subject_id}

                        </p>

                        <p>

                          <strong>
                            Semester:
                          </strong>

                          {' '}

                          {subject.semester}

                        </p>

                      </div>

                    ))

                  )
                  : (

                    <div className="empty-box">

                      No Subjects Found

                    </div>

                  )

                }

              </div>

            )

          }

        </div>

      </div>

    </div>

  );

}

export default SubjectManagementPage;
